 using Contoso.Text;

 namespace Contoso.Text.Tests;

 [TestClass]
 public class StringFormatterTests
 {
     private readonly StringFormatter _formatter = new();

     // ── FormatPhoneNumber ──────────────────────────────────────────────

     [TestMethod]
     public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber()
     {
         string result = _formatter.FormatPhoneNumber("1234567890");

         Assert.AreEqual("(123) 456-7890", result);
     }

     [TestMethod]
     public void FormatPhoneNumber_Result_StartsWithAreaCodeInParens()
     {
         string result = _formatter.FormatPhoneNumber("8005551234");

         StringAssert.StartsWith(result, "(800)");
     }

     [TestMethod]
     public void FormatPhoneNumber_Result_EndsWithLastFourDigits()
     {
         string result = _formatter.FormatPhoneNumber("8005551234");

         StringAssert.EndsWith(result, "1234");
     }

     [TestMethod]
     public void FormatPhoneNumber_Result_ContainsDashSeparator()
     {
         string result = _formatter.FormatPhoneNumber("8005551234");

         StringAssert.Contains(result, "-");
     }

     [TestMethod]
     public void FormatPhoneNumber_Result_MatchesPattern()
     {
         string result = _formatter.FormatPhoneNumber("8005551234");

         StringAssert.Matches(result, new(@"^\(\d{3}\) \d{3}-\d{4}$"));
     }

     [TestMethod]
     public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
     {
         Assert.ThrowsExactly<ArgumentNullException>(
             () => _formatter.FormatPhoneNumber(null!));
     }

     [TestMethod]
     [DataRow("123")]
     [DataRow("12345678901")]
     [DataRow("")]
     public void FormatPhoneNumber_WrongLength_ThrowsArgumentException(string digits)
     {
         Assert.ThrowsExactly<ArgumentException>(
             () => _formatter.FormatPhoneNumber(digits));
     }

     // ── BuildGreeting ──────────────────────────────────────────────────

     [TestMethod]
     public void BuildGreeting_DefaultTitle_ReturnsGreetingWithMr()
     {
         string result = _formatter.BuildGreeting("Smith");

         Assert.AreEqual("Dear Mr. Smith,", result);
     }

     [TestMethod]
     public void BuildGreeting_CustomTitle_ReturnsGreetingWithTitle()
     {
         string result = _formatter.BuildGreeting("Johnson", "Dr.");

         Assert.AreEqual("Dear Dr. Johnson,", result);
     }

     [TestMethod]
     public void BuildGreeting_Result_StartsWithDear()
     {
         string result = _formatter.BuildGreeting("Doe");

         StringAssert.StartsWith(result, "Dear ");
     }

     [TestMethod]
     public void BuildGreeting_Result_EndsWithComma()
     {
         string result = _formatter.BuildGreeting("Doe");

         StringAssert.EndsWith(result, ",");
     }

     [TestMethod]
     public void BuildGreeting_Result_ContainsName()
     {
         string result = _formatter.BuildGreeting("Williams", "Ms.");

         StringAssert.Contains(result, "Williams");
     }

     [TestMethod]
     public void BuildGreeting_NullName_ThrowsArgumentNullException()
     {
         Assert.ThrowsExactly<ArgumentNullException>(
             () => _formatter.BuildGreeting(null!));
     }

     [TestMethod]
     [DataRow("")]
     [DataRow("   ")]
     public void BuildGreeting_EmptyOrWhiteSpaceName_ThrowsArgumentException(string name)
     {
         Assert.ThrowsExactly<ArgumentException>(
             () => _formatter.BuildGreeting(name));
     }

     // ── GenerateSlug ───────────────────────────────────────────────────

     [TestMethod]
     public void GenerateSlug_SimpleTitle_ReturnsLowercaseSlug()
     {
         string result = _formatter.GenerateSlug("Hello World");

         Assert.AreEqual("hello-world", result);
     }

     [TestMethod]
     public void GenerateSlug_TitleWithSpecialChars_ReplacesWithDashes()
     {
         string result = _formatter.GenerateSlug("C# is great!!!");

         Assert.AreEqual("c-is-great", result);
     }

     [TestMethod]
     public void GenerateSlug_LeadingTrailingSpaces_TrimmedCleanly()
     {
         string result = _formatter.GenerateSlug("  padded title  ");

         StringAssert.DoesNotMatch(result, new(@"^-|-$"));
     }

     [TestMethod]
     public void GenerateSlug_Result_ContainsOnlyValidChars()
     {
         string result = _formatter.GenerateSlug("My Post: A & B?!");

         StringAssert.Matches(result, new(@"^[a-z0-9]+(-[a-z0-9]+)*$"));
     }

     [TestMethod]
     public void GenerateSlug_MultipleSpaces_CollapsedToSingleDash()
     {
         string result = _formatter.GenerateSlug("too   many    spaces");

         StringAssert.DoesNotMatch(result, new(@"--"));
     }

     [TestMethod]
